 1	import type { FC } from 'react';
 2	import SectionHeading from 'src/components/headers/SectionHeading';
 3	import { ModalHOC } from 'src/modules/Providers/modals/ModalHOC/ModalHOC';
 4	import { useForkliftTranslation } from 'src/utils/i18n';
 5	
 6	import { PageSection, PageSectionVariants, Stack } from '@patternfly/react-core';
 7	
 8	import { useProvider } from '../../hooks/useProvider';
 9	import type { ProviderDetailsPageProps } from '../../utils/types';
10	
11	import CredentialsSection from './components/CredentialsSection';
12	
13	const ProviderCredentialsTabPage: FC<ProviderDetailsPageProps> = ({ name, namespace }) => {
14	  const { t } = useForkliftTranslation();
15	  const { provider } = useProvider(name, namespace);
16	
17	  return (
18	    <ModalHOC>
19	      <PageSection variant={PageSectionVariants.light}>
20	        <Stack hasGutter>
21	          <SectionHeading text={t('Credentials')} />
22	          <CredentialsSection provider={provider} />
23	        </Stack>
24	      </PageSection>
25	    </ModalHOC>
26	  );
27	};
28	
29	export default ProviderCredentialsTabPage;

